import { useCallback } from 'react';

import { useCanvas } from '../hooks/useCanvas.js';
import { getCanvasColor } from '../utils/canvas-color.js';

interface RoundRectCanvasProps {
  x: number;
  y: number;
  width: number;
  height: number;
  color: string;
  borderRadius?: number;
  borderColor?: string;
  borderWidth?: number;
  opacity?: number;
}

export const RoundRectCanvas = (props: RoundRectCanvasProps) => {
  const {
    x,
    y,
    width,
    height,
    color,
    borderRadius = 0,
    borderColor = color,
    borderWidth = 0,
    opacity = 1,
  } = props;

  const draw = useCallback(
    (ctx: CanvasRenderingContext2D) => {
      ctx.beginPath();
      ctx.save();

      ctx.moveTo(x + borderRadius, y);
      ctx.lineTo(x + width - borderRadius, y);
      ctx.quadraticCurveTo(x + width, y, x + width, y + borderRadius);
      ctx.lineTo(x + width, y + height - borderRadius);
      ctx.quadraticCurveTo(
        x + width,
        y + height,
        x + width - borderRadius,
        y + height,
      );
      ctx.lineTo(x + borderRadius, y + height);
      ctx.quadraticCurveTo(x, y + height, x, y + height - borderRadius);
      ctx.lineTo(x, y + borderRadius);
      ctx.quadraticCurveTo(x, y, x + borderRadius, y);

      ctx.globalAlpha = opacity;
      ctx.lineWidth = borderWidth;
      ctx.fillStyle = getCanvasColor(color);
      ctx.fill();

      ctx.restore();

      ctx.strokeStyle = getCanvasColor(borderColor);
      ctx.stroke();

      ctx.restore();
      ctx.closePath();

      return false;
    },
    [x, y, width, height, color, borderRadius, borderColor, borderWidth],
  );

  useCanvas('round-rect', draw);

  return null;
};
